610	  return (
611	    <p
612	      style={{
613	        background: "rgba(232, 225, 211, 0.035)",
614	        border: "1px solid rgba(232, 225, 211, 0.12)",
615	        color: "var(--parchment-dim)",
616	        fontSize: "0.95rem",
617	        lineHeight: 1.55,
618	        margin: 0,
619	        padding: "1rem",
620	      }}
621	    >
622	      {children}
623	    </p>
624	  );
625	}
