627	function summarizeOpinion(opinion: PublicOpinion): string {
628	  if (opinion.abstention_reason) return opinion.abstention_reason;
629	  const body = stripMarkdown(opinion.body_markdown);
630	  return deriveExcerpt(body || opinion.event?.text || "", 140);
631	}
632	
633	function stripMarkdown(text: string): string {
634	  return text
635	    .replace(/\[(?:\d+|C:[^\]\s]+)\]/g, "the firm")
636	    .replace(/`([^`]+)`/g, "$1")
637	    .replace(/\*\*([^*]+)\*\*/g, "$1")
638	    .replace(/\*([^*]+)\*/g, "$1")
639	    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
640	    .replace(/[#>_-]+/g, " ")
641	    .replace(/\s+/g, " ")
642	    .trim();
643	}
644	
645	function formatTimestamp(value: string): string {
646	  const date = new Date(value);
647	  if (Number.isNaN(date.getTime())) return "Date pending";
648	
649	  return new Intl.DateTimeFormat("en-US", {
650	    day: "numeric",
651	    hour: "numeric",
652	    minute: "2-digit",
653	    month: "short",
654	    timeZone: "UTC",
655	    timeZoneName: "short",
656	    year: "numeric",
657	  }).format(date);
658	}
659	
660	function deriveExcerpt(text: string, limit = 300): string {
661	  const cleaned = text.replace(/\s+/g, " ").trim();
662	  if (!cleaned) return "(no preview available)";
663	  if (cleaned.length <= limit) return cleaned;
664	  const cut = cleaned.slice(0, limit);
665	  const lastSpace = cut.lastIndexOf(" ");
666	  return (lastSpace > limit * 0.65 ? cut.slice(0, lastSpace) : cut) + "…";
667	}
