65	  calibrationDiscountReason: string;
66	  payloadJson: string;
67	};
68	
69	type PublicResponseRow = {
70	  id: string;
71	  publishedConclusionId: string;
72	  kind: string;
73	  body: string;
74	  citationUrl: string;
75	  status: string;
76	  createdAt: Date;
77	  pseudonymous: boolean;
78	};
79	
80	export type PublicationPayloadJsonRow = {
81	  payloadJson: string;
82	  slug: string;
83	};
84	
85	const PUBLISHED_CONCLUSION_SELECT = {
86	  id: true,
87	  kind: true,
88	  slug: true,
89	  version: true,
90	  sourceConclusionId: true,
91	  publishedAt: true,
92	  doi: true,
93	  zenodoRecordId: true,
94	  discountedConfidence: true,
95	  statedConfidence: true,
96	  calibrationDiscountReason: true,
97	  payloadJson: true,
98	};
99	
100	const PUBLIC_RESPONSE_SELECT = {
101	  id: true,
102	  publishedConclusionId: true,
103	  kind: true,
104	  body: true,
105	  citationUrl: true,
106	  status: true,
107	  createdAt: true,
108	  pseudonymous: true,
109	};
110	
111	const PUBLIC_TITLE_MAX_CHARS = 70;
112	
113	function warnIfLongTitle(title: string) {
114	  const n = title.length;
115	  if (n > PUBLIC_TITLE_MAX_CHARS) {
116	    console.warn("[title-policy] long title (%d chars): %s", n, title);
117	  }
118	}
119	
120	function stringArray(value: unknown): string[] {
121	  return Array.isArray(value) ? value.filter((item): item is string => typeof item === "string") : [];
122	}
123	
124	function objectValue(value: unknown): Record<string, unknown> {
125	  return value && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : {};
126	}
127	
128	function optionalText(value: unknown): string | null {
129	  return typeof value === "string" && value.trim() ? value.trim() : null;
130	}
131	
132	function publicSourceUrl(value: unknown): string | null {
133	  if (typeof value !== "string") return null;
134	  const url = value.trim();
135	  if (!url) return null;
136	  if (/^\/(?:c|post|currents|forecasts)(?:\/|$)/.test(url)) return url;
137	  try {
138	    const parsed = new URL(url);
139	    return parsed.protocol === "https:" ? url : null;
140	  } catch {
141	    return null;
142	  }
143	}
144	
145	function parseArticlePayload(value: unknown): PublishedArticlePayload | undefined {
146	  const article = objectValue(value);
147	  const bodyMarkdown =
148	    typeof article.bodyMarkdown === "string" ? article.bodyMarkdown
149	    : typeof article.body_markdown === "string" ? article.body_markdown
150	    : "";
151	  const rawCitations = Array.isArray(article.citations) ? article.citations : [];
152	  const citations = rawCitations.flatMap((item, index): PublishedArticleCitation[] => {
153	    const citation = objectValue(item);
154	    const sourceKind =
155	      typeof citation.sourceKind === "string" ? citation.sourceKind
156	      : typeof citation.source_kind === "string" ? citation.source_kind
157	      : "";
158	    const sourceId =
159	      typeof citation.sourceId === "string" ? citation.sourceId
160	      : typeof citation.source_id === "string" ? citation.source_id
161	      : "";
162	    const quotedSpan =
163	      typeof citation.quotedSpan === "string" ? citation.quotedSpan
164	      : typeof citation.quoted_span === "string" ? citation.quoted_span
165	      : "";
166	    if (!sourceKind || !sourceId || !quotedSpan) return [];
167	    const publicUrl = publicSourceUrl(citation.publicUrl ?? citation.public_url);
168	    return [
169	      {
170	        label:
171	          typeof citation.label === "string" && citation.label.trim()
172	            ? citation.label.trim()
173	            : `S${index + 1}`,
174	        sourceKind,
175	        sourceId,
176	        quotedSpan,
177	        publicUrl,
178	        linkable: Boolean(publicUrl),
179	        sourceConclusionText: optionalText(citation.sourceConclusionText ?? citation.source_conclusion_text),
180	        sourceConclusionTitle: optionalText(citation.sourceConclusionTitle ?? citation.source_conclusion_title),
181	      },
182	    ];
183	  });
184	
185	  if (!bodyMarkdown && citations.length === 0) return undefined;
186	  return {
187	    kind: typeof article.kind === "string" ? article.kind : "",
188	    bodyMarkdown,
189	    sourceIds: stringArray(article.sourceIds ?? article.source_ids),
190	    ...(typeof article.sourceKey === "string" ? { sourceKey: article.sourceKey } : {}),
191	    citations,
192	  };
193	}
194	
195	export function parsePublicationPayload(row: PublicationPayloadJsonRow): PublishedPublicationPayload {
196	  let parsed: Record<string, unknown> = {};
197	  try {
198	    const value = JSON.parse(row.payloadJson);
199	    if (value && typeof value === "object" && !Array.isArray(value)) {
200	      parsed = value as Record<string, unknown>;
201	    }
202	  } catch {
203	    parsed = {};
204	  }
205	
206	  const strongestObjection =
207	    parsed.strongestObjection && typeof parsed.strongestObjection === "object" && !Array.isArray(parsed.strongestObjection)
208	      ? (parsed.strongestObjection as Record<string, unknown>)
209	      : {};
210	
211	  const citations: PublicCitation[] = Array.isArray(parsed.citations)
212	    ? parsed.citations.flatMap((item): PublicCitation[] => {
213	        if (!item || typeof item !== "object" || Array.isArray(item)) return [];
214	        const citation = item as Record<string, unknown>;
215	        if (
216	          (citation.format === "bibtex" || citation.format === "apa" || citation.format === "ris") &&
217	          typeof citation.block === "string"
218	        ) {
219	          return [{ format: citation.format, block: citation.block }];
220	        }
221	        return [];
222	      })
223	    : [];
224	
225	  const timeline =
226	    Array.isArray(parsed.timeline)
227	      ? parsed.timeline.flatMap((item): PublicationPayloadV1["timeline"] => {
228	          if (!item || typeof item !== "object" || Array.isArray(item)) return [];
229	          const event = item as Record<string, unknown>;
230	          if (typeof event.at !== "string" || typeof event.label !== "string") return [];
231	          return [
232	            {
233	              at: event.at,
234	              label: event.label,
235	              ...(typeof event.detail === "string" ? { detail: event.detail } : {}),
236	            },
237	          ];
238	        })
239	      : [];
240	
241	  const voiceComparisons =
242	    Array.isArray(parsed.voiceComparisons)
243	      ? parsed.voiceComparisons.flatMap((item): PublicationPayloadV1["voiceComparisons"] => {
244	          if (!item || typeof item !== "object" || Array.isArray(item)) return [];
245	          const voice = item as Record<string, unknown>;
246	          if (typeof voice.voice !== "string" || typeof voice.stance !== "string") return [];
247	          return [{ voice: voice.voice, stance: voice.stance }];
248	        })
249	      : [];
250	
251	  const exitConditions = stringArray(parsed.exitConditions);
252	  const whatWouldChangeOurMind = stringArray(parsed.whatWouldChangeOurMind);
253	  const article = parseArticlePayload(parsed.article);
254	
255	  return {
256	    schema: "theseus.publicConclusion.v1",
257	    conclusionText: typeof parsed.conclusionText === "string" ? parsed.conclusionText : row.slug,
258	    rationale: typeof parsed.rationale === "string" ? parsed.rationale : "",
259	    topicHint: typeof parsed.topicHint === "string" ? parsed.topicHint : "",
260	    evidenceSummary: typeof parsed.evidenceSummary === "string" ? parsed.evidenceSummary : "",
261	    exitConditions,
262	    strongestObjection: {
263	      objection: typeof strongestObjection.objection === "string" ? strongestObjection.objection : "",
264	      firmAnswer: typeof strongestObjection.firmAnswer === "string" ? strongestObjection.firmAnswer : "",
265	    },
266	    openQuestionsAdjacent: stringArray(parsed.openQuestionsAdjacent),
267	    voiceComparisons,
268	    methodology: parseMethodologyPayload(parsed.methodology),
269	    timeline,
270	    whatWouldChangeOurMind: whatWouldChangeOurMind.length ? whatWouldChangeOurMind : exitConditions,
271	    citations,
272	    ...(Array.isArray(parsed.internalLinks) ? { internalLinks: [] } : {}),
273	    ...(article ? { article } : {}),
274	  };
275	}
276	
277	function toPublishedConclusion(row: PublishedConclusionRow): PublishedConclusion {
278	  const payload = parsePublicationPayload(row);
279	  warnIfLongTitle(payload.conclusionText);
280	
281	  return {
282	    id: row.id,
283	    kind: row.kind || "CONCLUSION",
284	    slug: row.slug,
285	    version: row.version,
286	    sourceConclusionId: row.sourceConclusionId,
287	    publishedAt: row.publishedAt instanceof Date ? row.publishedAt.toISOString() : new Date(row.publishedAt).toISOString(),
288	    doi: row.doi,
289	    zenodoRecordId: row.zenodoRecordId,
290	    discountedConfidence: row.discountedConfidence,
291	    statedConfidence: row.statedConfidence,
292	    calibrationDiscountReason: row.calibrationDiscountReason,
293	    payload,
294	  };
295	}
296	
297	function toPublicResponse(row: PublicResponseRow): PublicResponse {
298	  return {
299	    id: row.id,
300	    publishedConclusionId: row.publishedConclusionId,
301	    kind: row.kind,
302	    body: row.body,
303	    citationUrl: row.citationUrl,
304	    status: row.status,
305	    createdAt: row.createdAt.toISOString(),
306	    pseudonymous: row.pseudonymous,
307	  };
308	}
309	
310	type DbFindMany<T> = {
311	  findMany: (args: Record<string, unknown>) => Promise<T[]>;
312	};
313	
314	type SourceLookupDb = {
315	  conclusion?: DbFindMany<{
316	    id: string;
317	    text: string;
318	    sources?: {
319	      upload?: {
320	        visibility: string;
321	        publishedAt: Date | string | null;
322	        slug: string | null;
323	      } | null;
324	    }[];
325	  }>;
326	  eventOpinion?: DbFindMany<{
327	    id: string;
328	    headline: string;
329	    revokedAt: Date | string | null;
330	  }>;
331	  forecastPrediction?: DbFindMany<{
332	    id: string;
333	    headline: string;
334	  }>;
335	};
336	
337	type CitationSourceMetadata = {
338	  sourceConclusionText: string | null;
339	  sourceConclusionTitle: string | null;
340	  publicLinkConfirmed: boolean;
341	};
342	
343	const CONCLUSION_SOURCE_KINDS = new Set(["conclusion", "claim", "principle", "firm_conclusion", "source_conclusion"]);
344	
345	function normalizedSourceKind(value: string): string {
346	  return value.trim().toLowerCase().replace(/[\s-]+/g, "_");
347	}
348	
349	function citationSourceKey(sourceKind: string, sourceId: string): string {
350	  return `${normalizedSourceKind(sourceKind)}:${sourceId}`;
351	}
352	
353	function idsForKind(sourceIdsByKind: Map<string, Set<string>>, ...sourceKinds: string[]): string[] {
354	  const ids = new Set<string>();
355	  for (const sourceKind of sourceKinds) {
356	    const sourceIds = sourceIdsByKind.get(normalizedSourceKind(sourceKind));
357	    if (!sourceIds) continue;
358	    for (const id of sourceIds) ids.add(id);
359	  }
360	  return [...ids];
361	}
362	
363	function collectArticleCitationSourceIds(rows: PublishedConclusion[]): Map<string, Set<string>> {
364	  const sourceIdsByKind = new Map<string, Set<string>>();
365	  for (const row of rows) {
366	    for (const citation of row.payload.article?.citations ?? []) {
367	      const sourceKind = normalizedSourceKind(citation.sourceKind);
368	      if (!sourceKind || !citation.sourceId) continue;
369	      const existing = sourceIdsByKind.get(sourceKind) ?? new Set<string>();
370	      existing.add(citation.sourceId);
371	      sourceIdsByKind.set(sourceKind, existing);
372	    }
373	  }
374	  return sourceIdsByKind;
375	}
376	
377	function hasPublicOrgUpload(
378	  sources:
379	    | {
380	        upload?: {
381	          visibility: string;
382	          publishedAt: Date | string | null;
383	          slug: string | null;
384	        } | null;
385	      }[]
386	    | undefined,
387	): boolean {
388	  return Boolean(
389	    sources?.some(({ upload }) => upload?.visibility === "org" && Boolean(upload.publishedAt) && Boolean(upload.slug)),
390	  );
391	}
392	
393	async function addConclusionCitationMetadata(
394	  organizationId: string,
395	  sourceIdsByKind: Map<string, Set<string>>,
396	  sourceMetadata: Map<string, CitationSourceMetadata>,
397	) {
398	  const ids = new Set<string>();
399	  for (const sourceKind of CONCLUSION_SOURCE_KINDS) {
400	    for (const id of idsForKind(sourceIdsByKind, sourceKind)) ids.add(id);
401	  }
402	  if (!ids.size) return;
403	
404	  const conclusionDb = (db as unknown as SourceLookupDb).conclusion;
405	  if (!conclusionDb) return;
406	
407	  const rows = await conclusionDb.findMany({
408	    where: { organizationId, id: { in: [...ids] } },
409	    select: {
410	      id: true,
411	      text: true,
412	      sources: {
413	        select: {
414	          upload: {
415	            select: {
416	              visibility: true,
417	              publishedAt: true,
418	              slug: true,
419	            },
420	          },
421	        },
422	      },
423	    },
424	  });
425	
426	  for (const row of rows) {
427	    const metadata = {
428	      sourceConclusionText: row.text,
429	      sourceConclusionTitle: null,
430	      publicLinkConfirmed: hasPublicOrgUpload(row.sources),
431	    };
432	    for (const sourceKind of CONCLUSION_SOURCE_KINDS) {
433	      sourceMetadata.set(citationSourceKey(sourceKind, row.id), metadata);
434	    }
435	  }
436	}
437	
438	async function addEventOpinionCitationMetadata(
439	  organizationId: string,
440	  sourceIdsByKind: Map<string, Set<string>>,
441	  sourceMetadata: Map<string, CitationSourceMetadata>,
442	) {
443	  const ids = idsForKind(sourceIdsByKind, "event_opinion", "correction");
444	  if (!ids.length) return;
445	
446	  const eventOpinionDb = (db as unknown as SourceLookupDb).eventOpinion;
447	  if (!eventOpinionDb) return;
448	
449	  const rows = await eventOpinionDb.findMany({
450	    where: { organizationId, id: { in: ids } },
451	    select: { id: true, headline: true, revokedAt: true },
452	  });
453	
454	  for (const row of rows) {
455	    const publicLinkConfirmed = !row.revokedAt;
456	    sourceMetadata.set(citationSourceKey("event_opinion", row.id), {
457	      sourceConclusionText: row.headline,
458	      sourceConclusionTitle: row.headline,
459	      publicLinkConfirmed,
460	    });
461	    sourceMetadata.set(citationSourceKey("correction", row.id), {
462	      sourceConclusionText: `Correction to: ${row.headline}`,
463	      sourceConclusionTitle: row.headline,
464	      publicLinkConfirmed,
465	    });
466	  }
467	}
468	
469	async function addForecastCitationMetadata(
470	  organizationId: string,
471	  sourceIdsByKind: Map<string, Set<string>>,
472	  sourceMetadata: Map<string, CitationSourceMetadata>,
473	) {
474	  const ids = idsForKind(sourceIdsByKind, "forecast_postmortem");
475	  if (!ids.length) return;
476	
477	  const forecastDb = (db as unknown as SourceLookupDb).forecastPrediction;
478	  if (!forecastDb) return;
479	
480	  const rows = await forecastDb.findMany({
481	    where: { organizationId, id: { in: ids } },
482	    select: { id: true, headline: true },
483	  });
484	
485	  for (const row of rows) {
486	    sourceMetadata.set(citationSourceKey("forecast_postmortem", row.id), {
487	      sourceConclusionText: row.headline,
488	      sourceConclusionTitle: row.headline,
489	      publicLinkConfirmed: true,
490	    });
491	  }
492	}
493	
494	async function enrichArticleCitationSources(
495	  rows: PublishedConclusion[],
496	  organizationId: string,
497	): Promise<PublishedConclusion[]> {
498	  const sourceIdsByKind = collectArticleCitationSourceIds(rows);
499	  if (!sourceIdsByKind.size) return rows;
500	
501	  const sourceMetadata = new Map<string, CitationSourceMetadata>();
502	  await Promise.all([
503	    addConclusionCitationMetadata(organizationId, sourceIdsByKind, sourceMetadata),
504	    addEventOpinionCitationMetadata(organizationId, sourceIdsByKind, sourceMetadata),
505	    addForecastCitationMetadata(organizationId, sourceIdsByKind, sourceMetadata),
506	  ]);
507	
508	  return rows.map((row) => {
509	    const article = row.payload.article;
510	    if (!article?.citations.length) return row;
511	
512	    return {
513	      ...row,
514	      payload: {
515	        ...row.payload,
516	        article: {
517	          ...article,
518	          citations: article.citations.map((citation) => {
519	            const metadata = sourceMetadata.get(citationSourceKey(citation.sourceKind, citation.sourceId));
520	            const sourceConclusionText = metadata?.sourceConclusionText ?? citation.sourceConclusionText;
521	            const sourceConclusionTitle = metadata?.sourceConclusionTitle ?? citation.sourceConclusionTitle;
522	            const publicUrl = metadata?.publicLinkConfirmed && citation.publicUrl ? citation.publicUrl : null;
523	            return {
524	              ...citation,
525	              sourceConclusionText,
526	              sourceConclusionTitle,
527	              publicUrl,
528	              linkable: Boolean(publicUrl),
529	            };
530	          }),
531	        },
532	      },
533	    };
534	  });
535	}
536	
537	export async function resolvePublicOrganizationId(): Promise<string | null> {
538	  const explicitId = (
539	    process.env.THESEUS_PUBLIC_ORG_ID?.trim() ||
540	    process.env.CURRENTS_INGEST_ORG_ID?.trim() ||
541	    ""
542	  );
543	  if (explicitId) {
544	    const org = await db.organization.findUnique({
545	      where: { id: explicitId },
546	      select: { id: true, deletedAt: true },
547	    });
548	    return org && !org.deletedAt ? org.id : null;
549	  }
550	
551	  const slug =
552	    process.env.THESEUS_PUBLIC_ORG_SLUG?.trim() ||
553	    process.env.DEFAULT_ORGANIZATION_SLUG?.trim() ||
554	    process.env.NEXT_PUBLIC_DEFAULT_ORG_SLUG?.trim() ||
555	    "";
556	
557	  if (slug) {
558	    const org = await db.organization.findUnique({
559	      where: { slug },
560	      select: { id: true, deletedAt: true },
561	    });
562	    return org && !org.deletedAt ? org.id : null;
563	  }
564	
565	  const orgs = await db.organization.findMany({
566	    where: { deletedAt: null },
567	    orderBy: { createdAt: "asc" },
568	    take: 2,
569	    select: { id: true },
570	  });
571	  return orgs.length === 1 ? orgs[0].id : null;
572	}
573	
574	export async function listPublishedConclusions(): Promise<PublishedConclusion[]> {
575	  const organizationId = await resolvePublicOrganizationId();
576	  if (!organizationId) return [];
577	
578	  const rows = await db.publishedConclusion.findMany({
579	    where: { organizationId },
580	    orderBy: [{ slug: "asc" }, { version: "asc" }],
581	    select: PUBLISHED_CONCLUSION_SELECT,
582	  });
583	  return enrichArticleCitationSources((rows as PublishedConclusionRow[]).map(toPublishedConclusion), organizationId);
584	}
585	
586	export async function listPublishedConclusionsForFeed(): Promise<PublishedConclusion[]> {
587	  const organizationId = await resolvePublicOrganizationId();
588	  if (!organizationId) return [];
589	
590	  const rows = await db.publishedConclusion.findMany({
591	    where: { organizationId },
592	    orderBy: { publishedAt: "desc" },
593	    select: PUBLISHED_CONCLUSION_SELECT,
594	  });
595	  return enrichArticleCitationSources((rows as PublishedConclusionRow[]).map(toPublishedConclusion), organizationId);
596	}
597	
598	export async function listPublishedArticles(limit = 8): Promise<PublishedConclusion[]> {
599	  const organizationId = await resolvePublicOrganizationId();
600	  if (!organizationId) return [];
601	
602	  try {
603	    const rows = await db.$queryRaw<PublishedConclusionRow[]>`
604	      SELECT
605	        id,
606	        kind,
607	        slug,
608	        version,
609	        "sourceConclusionId",
610	        "publishedAt",
611	        doi,
612	        "zenodoRecordId",
613	        "discountedConfidence",
614	        "statedConfidence",
615	        "calibrationDiscountReason",
616	        "payloadJson"
617	      FROM "PublishedConclusion"
618	      WHERE "organizationId" = ${organizationId}
619	        AND kind = 'ARTICLE'
620	      ORDER BY "publishedAt" DESC
621	      LIMIT ${limit}
622	    `;
623	    return enrichArticleCitationSources(rows.map(toPublishedConclusion), organizationId);
624	  } catch (error) {
625	    console.error("[public] article query failed (schema lag?):", error);
626	    return [];
627	  }
628	}
629	
630	export async function getConclusionBySlug(slug: string): Promise<PublishedConclusion | null> {
631	  const organizationId = await resolvePublicOrganizationId();
632	  if (!organizationId) return null;
633	
634	  const rows = await db.publishedConclusion.findMany({
635	    where: { organizationId, slug },
636	    orderBy: { version: "desc" },
637	    take: 1,
638	    select: PUBLISHED_CONCLUSION_SELECT,
639	  });
640	  const row = rows[0] as PublishedConclusionRow | undefined;
641	  return row ? (await enrichArticleCitationSources([toPublishedConclusion(row)], organizationId))[0] : null;
642	}
643	
644	export async function getConclusionVersion(slug: string, version: number): Promise<PublishedConclusion | null> {
645	  const organizationId = await resolvePublicOrganizationId();
646	  if (!organizationId) return null;
647	
648	  const row = await db.publishedConclusion.findFirst({
649	    where: { organizationId, slug, version },
650	    select: PUBLISHED_CONCLUSION_SELECT,
651	  });
652	  return row ? (await enrichArticleCitationSources([toPublishedConclusion(row as PublishedConclusionRow)], organizationId))[0] : null;
653	}
654	
655	export async function listConclusionVersions(slug: string): Promise<PublishedConclusion[]> {
656	  const organizationId = await resolvePublicOrganizationId();
657	  if (!organizationId) return [];
658	
659	  const rows = await db.publishedConclusion.findMany({
660	    where: { organizationId, slug },
661	    orderBy: { version: "asc" },
662	    select: PUBLISHED_CONCLUSION_SELECT,
663	  });
664	  return enrichArticleCitationSources((rows as PublishedConclusionRow[]).map(toPublishedConclusion), organizationId);
665	}
666	
667	export async function responsesForPublishedId(publishedConclusionId: string): Promise<PublicResponse[]> {
668	  const organizationId = await resolvePublicOrganizationId();
669	  if (!organizationId) return [];
670	
671	  const rows = await db.publicResponse.findMany({
672	    where: {
673	      organizationId,
674	      publishedConclusionId,
675	      status: { in: ["approved", "engaged"] },
676	    },
677	    orderBy: { createdAt: "desc" },
678	    select: PUBLIC_RESPONSE_SELECT,
679	  });
680	  return (rows as PublicResponseRow[]).map(toPublicResponse);
681	}
682	
683	export async function buildPublishedBundle(): Promise<PublishedBundle> {
684	  const conclusions = await listPublishedConclusions();
685	  const responses = conclusions.length
686	    ? await Promise.all(conclusions.map((row) => responsesForPublishedId(row.id))).then((groups) => groups.flat())
687	    : [];
688	
689	  return {
690	    schema: "theseus.publishedExport.v1",
691	    generatedAt: new Date().toISOString(),
692	    conclusions,
693	    openQuestions: [],
694	    responses,
695	  };
696	}
