1	import { db } from "@/lib/db";
2	
3	/**
4	 * OpenQuestion read/write surface for the founder triage queue and
5	 * the public methodology page.
6	 *
7	 * Two responsibilities:
8	 *
9	 *   1. Compute a bounded priority score for each `OpenQuestion`. The
10	 *      authoritative scorer is `noosphere/evaluation/question_priority.py`;
11	 *      this is its TS shadow, working from the columns Prisma actually
12	 *      stores. Same three-component philosophy:
13	 *
14	 *        - centrality      → how many existing conclusions reference
15	 *                            either of the two claims this question is
16	 *                            "about". Saturating curve so a 50-link
17	 *                            question doesn't drown a 5-link one.
18	 *        - replayability   → cheap proxy from `unresolvedReason` text:
19	 *                            "literature", "lookup", "ask" → cheap;
20	 *                            "rerun", "replicate", "embargo" → expensive.
21	 *        - calibration     → thinness of the firm's track record in the
22	 *                            question's domain (derived from the linked
23	 *                            claims' domains).
24	 *
25	 *      Weights are normalized so centrality alone cannot dominate the
26	 *      final score (the prompt's pinned constraint).
27	 *
28	 *   2. Strict public-visibility filter. A question is public-visible
29	 *      iff both of its linked claims have a `PublishedConclusion` row.
30	 *      Anything else is firm-internal triage and stays inside the
31	 *      founder workspace.
32	 */
33	
34	export type OpenQuestionRow = {
35	  id: string;
36	  summary: string;
37	  unresolvedReason: string;
38	  layerDisagreementSummary: string;
39	  claimAId: string;
40	  claimBId: string;
41	  createdAt: Date;
42	};
43	
44	export type DomainFootprint = {
45	  domain: string;
46	  resolvedForecastCount: number;
47	};
48	
49	export type PriorityComponent = {
50	  name: "centrality" | "replayability" | "calibration_relevance";
51	  raw: number;
52	  weight: number;
53	  contribution: number;
54	};
55	
56	export type PriorityScore = {
57	  questionId: string;
58	  score: number;
59	  components: PriorityComponent[];
60	};
61	
62	export type TriageRow = OpenQuestionRow & {
63	  priority: PriorityScore;
64	  linkedConclusionCount: number;
65	  domain: string;
66	  candidateMethodNames: string[];
67	};
68	
69	const DEFAULT_WEIGHTS = {
70	  centrality: 0.4,
71	  replayability: 0.3,
72	  calibration_relevance: 0.3,
73	} as const;
74	
75	const CENTRALITY_SATURATION = 8;
76	const CALIBRATION_THICK_THRESHOLD = 30;
77	
78	const CHEAP_RESOLUTION_HINTS = [
79	  "literature",
80	  "lookup",
81	  "reading",
82	  "cite",
83	  "ask",
84	  "search",
85	  "google",
86	  "documented",
87	];
88	
89	const EXPENSIVE_RESOLUTION_HINTS = [
90	  "rerun",
91	  "replicate",
92	  "embargo",
93	  "year of",
94	  "long-horizon",
95	  "longitudinal",
96	  "experiment",
97	  "build a",
98	  "instrument",
99	];
100	
101	function clip01(x: number): number {
102	  if (Number.isNaN(x)) return 0;
103	  if (x < 0) return 0;
104	  if (x > 1) return 1;
105	  return x;
106	}
107	
108	function centralityScore(linkedConclusionCount: number): number {
109	  return clip01(linkedConclusionCount / CENTRALITY_SATURATION);
110	}
111	
112	function replayabilityScore(reasonText: string): number {
113	  const text = (reasonText ?? "").toLowerCase();
114	  if (!text) return 0.5;
115	  let score = 0.5;
116	  for (const hint of CHEAP_RESOLUTION_HINTS) {
117	    if (text.includes(hint)) {
118	      score = Math.max(score, 0.85);
119	    }
120	  }
121	  for (const hint of EXPENSIVE_RESOLUTION_HINTS) {
122	    if (text.includes(hint)) {
123	      score = Math.min(score, 0.2);
124	    }
125	  }
126	  return clip01(score);
127	}
128	
129	function calibrationRelevanceScore(footprint: DomainFootprint | null): number {
130	  if (!footprint) return 0.5;
131	  const thinness = clip01(
132	    1 - footprint.resolvedForecastCount / CALIBRATION_THICK_THRESHOLD,
133	  );
134	  return thinness;
135	}
136	
137	export type ScoreInputs = {
138	  linkedConclusionCount: number;
139	  unresolvedReason: string;
140	  domainFootprint: DomainFootprint | null;
141	};
142	
143	export function scoreOpenQuestion(
144	  questionId: string,
145	  inputs: ScoreInputs,
146	  weights: Partial<typeof DEFAULT_WEIGHTS> = {},
147	): PriorityScore {
148	  const w = { ...DEFAULT_WEIGHTS, ...weights };
149	  const sum = w.centrality + w.replayability + w.calibration_relevance;
150	  if (sum <= 0) {
151	    return scoreOpenQuestion(questionId, inputs, DEFAULT_WEIGHTS);
152	  }
153	  const norm = {
154	    centrality: w.centrality / sum,
155	    replayability: w.replayability / sum,
156	    calibration_relevance: w.calibration_relevance / sum,
157	  };
158	
159	  const rawCentral = centralityScore(inputs.linkedConclusionCount);
160	  const rawReplay = replayabilityScore(inputs.unresolvedReason);
161	  const rawCalib = calibrationRelevanceScore(inputs.domainFootprint);
162	
163	  const components: PriorityComponent[] = [
164	    {
165	      name: "centrality",
166	      raw: rawCentral,
167	      weight: norm.centrality,
168	      contribution: rawCentral * norm.centrality,
169	    },
170	    {
171	      name: "replayability",
172	      raw: rawReplay,
173	      weight: norm.replayability,
174	      contribution: rawReplay * norm.replayability,
175	    },
176	    {
177	      name: "calibration_relevance",
178	      raw: rawCalib,
179	      weight: norm.calibration_relevance,
180	      contribution: rawCalib * norm.calibration_relevance,
181	    },
182	  ];
183	
184	  const score = clip01(
185	    components.reduce((acc, c) => acc + c.contribution, 0),
186	  );
187	  return { questionId, score, components };
188	}
