198	async function loadLinkedClaimMap(
199	  organizationId: string,
200	  ids: string[],
201	): Promise<Map<string, ConclusionJoin>> {
202	  if (ids.length === 0) return new Map();
203	  const conclusions = await db.conclusion.findMany({
204	    where: { organizationId, id: { in: ids } },
205	    select: { id: true },
206	  });
207	  const knownIds = conclusions.map((c) => c.id);
208	  if (knownIds.length === 0) return new Map();
209	  const methods = await db.conclusionMethod.findMany({
210	    where: { organizationId, conclusionId: { in: knownIds } },
211	    select: {
212	      conclusionId: true,
213	      domain: true,
214	      methodName: true,
215	      weight: true,
216	    },
217	    orderBy: { weight: "desc" },
218	  });
219	  const byConclusion = new Map<string, ConclusionJoin>();
220	  for (const id of knownIds) {
221	    byConclusion.set(id, { id, domain: null, methodUsed: null });
222	  }
223	  for (const m of methods) {
224	    const existing = byConclusion.get(m.conclusionId);
225	    if (!existing) continue;
226	    if (!existing.domain && m.domain) existing.domain = m.domain;
227	    if (!existing.methodUsed && m.methodName) existing.methodUsed = m.methodName;
228	  }
229	  return byConclusion;
230	}
231	
232	async function buildDomainFootprints(
233	  organizationId: string,
234	  domains: Iterable<string>,
235	): Promise<Map<string, DomainFootprint>> {
236	  const out = new Map<string, DomainFootprint>();
237	  const unique = Array.from(new Set([...domains].filter(Boolean)));
238	  if (unique.length === 0) return out;
239	  // Aggregate sample sizes across methods per domain. Thicker domains
240	  // (more resolved forecasts feeding any method) score lower on the
241	  // calibration-relevance component.
242	  const rows = await db.methodTrackRecord.findMany({
243	    where: { organizationId, domain: { in: unique } },
244	    select: { domain: true, sampleSize: true },
245	  });
246	  for (const d of unique) out.set(d, { domain: d, resolvedForecastCount: 0 });
247	  for (const r of rows) {
248	    const cur = out.get(r.domain);
249	    if (cur) cur.resolvedForecastCount += r.sampleSize;
250	  }
251	  return out;
252	}
253	
254	function inferDomain(joins: ConclusionJoin[]): string {
255	  const counts = new Map<string, number>();
256	  for (const j of joins) {
257	    const d = (j.domain ?? "").trim();
258	    if (!d) continue;
259	    counts.set(d, (counts.get(d) ?? 0) + 1);
260	  }
261	  let best = "";
262	  let bestN = 0;
263	  for (const [d, n] of counts) {
264	    if (n > bestN) {
265	      best = d;
266	      bestN = n;
267	    }
268	  }
269	  return best;
270	}
271	
272	export async function loadTriageQueue(
273	  organizationId: string,
274	  options: { domain?: string; limit?: number } = {},
275	): Promise<TriageRow[]> {
276	  const rows = await db.openQuestion.findMany({
277	    where: { organizationId },
278	    orderBy: { createdAt: "desc" },
279	    take: options.limit ?? 200,
280	  });
281	
282	  const claimIds = Array.from(
283	    new Set(rows.flatMap((r) => [r.claimAId, r.claimBId])),
284	  );
285	  const claimMap = await loadLinkedClaimMap(organizationId, claimIds);
286	
287	  const allDomains = new Set<string>();
288	  for (const r of rows) {
289	    const a = claimMap.get(r.claimAId);
290	    const b = claimMap.get(r.claimBId);
291	    for (const j of [a, b]) {
292	      if (j?.domain) allDomains.add(j.domain);
293	    }
294	  }
295	  const footprints = await buildDomainFootprints(organizationId, allDomains);
296	
297	  const triage = rows.map((r) => {
298	    const a = claimMap.get(r.claimAId);
299	    const b = claimMap.get(r.claimBId);
300	    const linked = [a, b].filter(Boolean) as ConclusionJoin[];
301	    const domain = inferDomain(linked);
302	    const candidateMethods = Array.from(
303	      new Set(
304	        linked
305	          .map((j) => (j.methodUsed ?? "").trim())
306	          .filter((s): s is string => Boolean(s)),
307	      ),
308	    );
309	    const linkedConclusionCount = linked.length;
310	    const priority = scoreOpenQuestion(r.id, {
311	      linkedConclusionCount,
312	      unresolvedReason: r.unresolvedReason,
313	      domainFootprint: domain ? footprints.get(domain) ?? null : null,
314	    });
315	    return {
316	      id: r.id,
317	      summary: r.summary,
318	      unresolvedReason: r.unresolvedReason,
319	      layerDisagreementSummary: r.layerDisagreementSummary,
320	      claimAId: r.claimAId,
321	      claimBId: r.claimBId,
322	      createdAt: r.createdAt,
323	      priority,
324	      linkedConclusionCount,
325	      domain,
326	      candidateMethodNames: candidateMethods,
327	    } satisfies TriageRow;
328	  });
329	
330	  const filtered = options.domain
331	    ? triage.filter((t) => t.domain === options.domain)
332	    : triage;
333	  return filtered.sort((a, b) => b.priority.score - a.priority.score);
334	}
