336	export async function listOpenQuestionDomains(
337	  organizationId: string,
338	): Promise<string[]> {
339	  const rows = await db.openQuestion.findMany({
340	    where: { organizationId },
341	    select: { claimAId: true, claimBId: true },
342	  });
