392	// ── Public surface ─────────────────────────────────────────────────────────
393	
394	export type PublicOpenQuestion = {
395	  id: string;
396	  summary: string;
397	  createdAt: Date;
398	  domain: string;
399	  candidateMethodNames: string[];
400	  /**
401	   * Public-visible conclusion ids whose published confidence depends on
402	   * this question being resolved. Only `PublishedConclusion` rows are
403	   * surfaced; firm-internal claims are filtered out by construction.
404	   */
405	  gatedPublishedConclusionIds: string[];
406	};
407	
408	/**
409	 * Strict public-visibility filter: a question is rendered publicly iff
410	 * BOTH of its linked claims have a `PublishedConclusion` row. The
411	 * symmetry is intentional — a question that touches one published claim
412	 * and one private internal claim is still firm-internal gossip and is
413	 * suppressed.
414	 */
415	export async function loadPublicOpenQuestions(
416	  organizationId: string,
417	  options: { limit?: number } = {},
418	): Promise<PublicOpenQuestion[]> {
419	  const rows = await db.openQuestion.findMany({
420	    where: { organizationId },
421	    orderBy: { createdAt: "desc" },
422	    take: options.limit ?? 80,
423	  });
424	
425	  const claimIds = Array.from(
426	    new Set(rows.flatMap((r) => [r.claimAId, r.claimBId])),
427	  );
428	  if (claimIds.length === 0) return [];
429	
430	  const claimMap = await loadLinkedClaimMap(organizationId, claimIds);
431	
432	  const publishedRows = await db.publishedConclusion.findMany({
433	    where: {
434	      organizationId,
435	      sourceConclusionId: { in: claimIds },
436	    },
437	    select: { id: true, sourceConclusionId: true },
438	  });
439	  const publishedByClaim = new Map<string, string[]>();
440	  for (const p of publishedRows) {
441	    const existing = publishedByClaim.get(p.sourceConclusionId) ?? [];
442	    existing.push(p.id);
443	    publishedByClaim.set(p.sourceConclusionId, existing);
444	  }
445	
446	  const out: PublicOpenQuestion[] = [];
447	  for (const r of rows) {
448	    const aPub = publishedByClaim.get(r.claimAId);
449	    const bPub = publishedByClaim.get(r.claimBId);
450	    if (!aPub || !bPub) continue; // strict filter
451	    const a = claimMap.get(r.claimAId);
452	    const b = claimMap.get(r.claimBId);
453	    const linked = [a, b].filter(Boolean) as ConclusionJoin[];
454	    const domain = inferDomain(linked);
455	    const candidates = Array.from(
456	      new Set(
457	        linked
458	          .map((j) => (j.methodUsed ?? "").trim())
459	          .filter((s): s is string => Boolean(s)),
460	      ),
461	    );
462	    out.push({
463	      id: r.id,
464	      summary: r.summary,
465	      createdAt: r.createdAt,
466	      domain,
467	      candidateMethodNames: candidates,
468	      gatedPublishedConclusionIds: [...aPub, ...bPub],
469	    });
470	  }
471	  return out;
472	}
