function RailHeader({
  href,
  linkLabel,
  title,
  titleId,
}: {
  href?: string;
  linkLabel?: string;
  title: string;
  titleId: string;
}) {
  return (
    <div
      style={{
        alignItems: "center",
        display: "flex",
        flexWrap: "wrap",
        gap: "0.8rem",
        justifyContent: "space-between",
        marginBottom: "0.85rem",
      }}
